#pragma once

#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <unistd.h>

#include <cerrno>
#include <cstdint>
#include <cstring>
#include <span>
#include <stdexcept>
#include <string>

// Owns a host file mapped into memory and exposes it as std::span<uint8_t>.
class MmapBacking
{
public:
  MmapBacking(const std::string& path, std::size_t size) : size_(size)
  {
    fd_ = ::open(path.c_str(), O_RDWR | O_CREAT, 0600);
    if (fd_ < 0)
      throw std::runtime_error("MmapBacking: open(" + path
                               + ") failed: " + std::strerror(errno));
    if (::ftruncate(fd_, static_cast<off_t>(size_)) != 0) {
      auto err = std::strerror(errno);
      ::close(fd_);
      fd_ = -1;
      throw std::runtime_error("MmapBacking: ftruncate failed: "
                               + std::string{err});
    }
    // MAP_POPULATE prefaults pages so the first sweep of writes (e.g. ELF
    // loading) does not stall on per-page faults.
    void* p = ::mmap(nullptr, size_, PROT_READ | PROT_WRITE,
                     MAP_SHARED | MAP_POPULATE, fd_, 0);
    if (p == MAP_FAILED) {
      auto err = std::strerror(errno);
      ::close(fd_);
      fd_ = -1;
      throw std::runtime_error("MmapBacking: mmap failed: " + std::string{err});
    }
    base_ = static_cast<uint8_t*>(p);
  }

  ~MmapBacking()
  {
    if (base_ != nullptr)
      ::munmap(base_, size_);
    if (fd_ >= 0)
      ::close(fd_);
  }

  MmapBacking(const MmapBacking&) = delete;
  MmapBacking& operator=(const MmapBacking&) = delete;
  MmapBacking(MmapBacking&&) = delete;
  MmapBacking& operator=(MmapBacking&&) = delete;

  auto span() -> std::span<uint8_t> { return {base_, size_}; }

private:
  int fd_ = -1;
  uint8_t* base_ = nullptr;
  std::size_t size_ = 0;
};

