  if (args.save_ctx || args.continue_ctx || args.context_dir != "./saved_ctx/")
  {
    spdlog::critical(
      "--save, --continue, and --context-dir require VSIMSAVABLE build");
    std::exit(EXIT_FAILURE);
  }
#endif

  if (!args.resume_from_qemu.empty() && args.continue_ctx)
    throw std::runtime_error(
      "--resume-from-qemu and --continue are mutually exclusive");

  print_version();

  // systemc and cci init
  auto broker = cci_utils::broker{"global_broker"};
  cci::cci_register_broker(broker);

  const auto time_resolution = sc_core::sc_get_time_resolution();
  spdlog::debug("Using time resolution: {}", time_resolution.to_string());

  std::optional<MmapBacking> shared_ram;
  if (!args.shared_mem_path.empty()) {
    if (args.shared_mem_size == 0)
      throw std::runtime_error(
        "--shared-mem-path requires --shared-mem-size > 0");
    shared_ram.emplace(args.shared_mem_path, args.shared_mem_size);
  } else if (args.shared_mem_size != 0) {
    throw std::runtime_error(
      "--shared-mem-size requires --shared-mem-path");
  }

  // Hybrid mode: the mmap window is the only RAM; QEMU virt has no alias.
  const MemoryRegion ram_region = shared_ram
    ? MemoryRegion{args.shared_mem_base,
                   args.shared_mem_base + args.shared_mem_size - 1}
    : MemoryRegion{RAM_BASE, RAM_END};
  const MemoryRegion ram_alias_region = shared_ram
    ? MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
                   SimpleMemory<32>::INVALID_ADDRESS}
    : MemoryRegion{RAM_ALIAS_BASE, RAM_ALIAS_END};

  // run simulation
  const auto do_sim = [&]<typename CPU>() -> int {
    Simulator<CPU> sim{
      "sim",
      shared_ram ? shared_ram->span() : std::span<uint8_t>{},
      ram_region, ram_alias_region};

    if (args.memmap) {
      sim.platform.interconnect.dump_region();
      return 0;
    }

    sim.set_mem_latency(args.mem_latency);

    if (!args.ilm_file.empty())
      sim.load_image(args.ilm_file, MEM_TYPE::ILM);

    if (!args.dlm_file.empty())
      sim.load_image(args.dlm_file, MEM_TYPE::DLM);

