#pragma once

#include <zlib.h>

#include <cstdint>

#include <span>
#include <stdexcept>
#include <string>

// Dump/load a byte buffer using two gzip chunks.
// gzwrite accepts at most 2^31-1 bytes per call, so large buffers are split.

inline void dump_gz_memory(const std::span<const uint8_t> mem,
                           const std::string& path)
{
  const size_t half = mem.size() / 2;
  const struct
  {
    const char* suffix;
    size_t offset;
    size_t size;
  } chunks[] = {{".0", 0, half}, {".1", half, mem.size() - half}};

  for (const auto& c: chunks) {
    gzFile f = gzopen((path + c.suffix).c_str(), "wb");
    if (!f)
      throw std::runtime_error("Failed to open for writing: " + path
                               + c.suffix);
    gzwrite(f, mem.data() + c.offset, c.size);
    gzclose(f);
  }
}

inline void load_gz_memory(const std::span<uint8_t> mem,
                           const std::string& path)
{
  const size_t half = mem.size() / 2;
  const struct
  {
    const char* suffix;
    size_t offset;
    size_t size;
  } chunks[] = {{".0", 0, half}, {".1", half, mem.size() - half}};

  for (const auto& c: chunks) {
    gzFile f = gzopen((path + c.suffix).c_str(), "rb");
    if (!f)
      throw std::runtime_error("Failed to open for reading: " + path
                               + c.suffix);
    gzread(f, mem.data() + c.offset, c.size);
    gzclose(f);
  }
}

